func TestSearchFields_GenderChoice(t *testing.T) {
	t.Parallel()
	r := newTestSearchFieldsResolver()

	fields, err := r.SearchFields(context.Background())
	if err != nil {
		t.Fatalf("SearchFields returned error: %v", err)
	}

	f := findFieldByName(t, fields, "gender")
	cf, ok := f.(*model.ChoiceSearchField)
	if !ok {
		t.Fatalf("gender: got %T, want *model.ChoiceSearchField", f)
	}
	if len(cf.Options) != 3 {
		t.Errorf("gender options count: got %d, want 3", len(cf.Options))
	}
	if cf.MaxSelections == nil || *cf.MaxSelections != 1 {
		t.Errorf("gender MaxSelections: got %v, want ptr(1)", cf.MaxSelections)
	}
